('43', 'Guest', '<h3><font face="tahoma,arial,helvetica,sans-serif">سلام چط<sub>ور<sup><em>ی ؟</em></sup></sub></font><font face="tahoma,arial,helvetica,sans-serif"><sup><em>سلا</em></sup><strong><em><sup>م</sup> چطو</em>ری ؟</strong></font><font face="tahoma,arial,helvetica,sans-serif"><strong>سلام </strong>چطوری ؟</font></h3>', '111', '111', '', 'yes', 17, '20101104082255', '2010/11/04', '1389/08/13', '8:22:55', '2010/11/04', '1389/08/13', '8:23:22'),
('35', 'user', 'کارهایی که باید انجام بشه تا سایت راه بیفته :  1 - تنظیم محتوای اولیه سیستم خبری  2 - تنظیم شاخه ها و زیر شاخه های تالار گفتگو  3 - تنظیمات سیستم گالری عکس', 'http://site.com', 'asd@asd.com', NULL, 'yes', 3, '', NULL, '1388/2/2', NULL, '2010/10/15', '1389/07/23', '8:13:28'),
(NULL, '', '', '', '', NULL, 'yes', 4, '20101008084656', '2010/10/08', '1389/07/16', '8:46:56', '2010/10/15', '1389/07/23', '8:13:31'),
