(4, 'سلام چطوری ؟', '0', NULL, NULL, '20101101115237', '2010/11/01', '1389/08/10', 'سلام چطوری ؟', 'متن این پیغام کتملا محرمانه میباشد !!!!', '', NULL, NULL, NULL, NULL, '2'),
(7, 'سوال مهم', '0', NULL, NULL, '20101101150544', '2010/11/01', '1389/08/10', 'سوال مهم', 'رئيس جمهور درآغاز گفتگوي زنده تلويزيوني با شبکه يک سيما گفت: انقلاب اسلامي يک انفجار نور و رحمت بود. آقاي احمدي‌نژاد درباره سفر اخيرش به لبنان و دليل استقبال بي‌نظير مردم لبنان از وي اظهار داشت: انقلاب اسلامي اعلام آغاز پايان يک دوران سياه بود.\r\n\r\nوي ادامه داد: روندي با انقلاب اسلامي آغاز شد که يک دوره سياه بر بشر رو به افول گذاشت.\r\n\r\nرئيس جمهور اضافه کرد: حاکميت انديشه‌هاي مادي همه هويت و حيثيت انسان‌ها را متلاشي کرده بود که يک وجه آن جنگ و کشتارها، وجه ديگر آن استعمار و غارت‌ها، کينه‌ورزي‌ها، تحقير ملت‌ها، فقر و فاصله طبقاتي بود.\r\n\r\nآقاي احمدي‌نژاد گفت: همه اينها به خاطر اين بود که انسان از هويت و حقيقت خود دور افتاده بود.\r\n\r\nوي تصريح کرد: انقلاب اسلامي فرياد زد انسان‌ها به خود، آسمان، حقيقت زندگي، اصل زيبايي، اصل عشق و محبت و اصل دوستي برگردند.\r\n\r\nرئيس جمهور گفت: اين حرف ظاهرش ساده است، اما بايد ديد در مقابل چه جرياني و در چه فضايي مطرح شده است و چه ارتباطي با قلب و فطرت انسان‌ها دارد.\r\n\r\n\r\nبيداري ملت‌ها شروع شده است\r\n\r\nآقاي احمدي‌نژاد افزود: عکس العمل گسترده توده‌هاي مردم، انديشمندان، هنرمندان، صاحبنظران، دلسوزان و آحاد مردم در دنيا شروع شد.\r\n\r\nوي ادامه داد: امروز ما به دوران بلوغ اين انديشه در سطح جهان نزديک مي‌شويم؛ سفر لبنان يک برش از اين انديشه و همان چيزي است که در استان هاي گلستان، اردبيل و قم مي‌بينيد.\r\n\r\nرئيس جمهور گفت: هر جاي دنيا مي‌رويم حرف‌ها همين است، اگر فضاي آزادي باشد و مردم بتوانند اظهار نظر کنند، حرف همين است.\r\n\r\nوي افزود: برخي گفتند در لبنان فقط مسلمانان استقبال کردند، اما مسيحي‌ها هم با همان احساس بودند، به طوري که گويي دوستان چند هزار ساله هستيم و از يک ريشه‌ايم.\r\n\r\nآقاي احمدي‌نژاد گفت: بيداري ملت‌ها شروع شده است و به سرعت به نقطه اوج خود نزديک مي‌شود. وي اضافه کرد: اگر اين، همه‌گير و نهادينه شود و آن طور که هست دريافت شود، ديگر جايي براي قدرتمندان، ظلم، زور، تحميل، رژيم صهيونيستي، اشغالگري و تجاوز در عالم باقي نمي‌ماند.\r\n\r\n\r\nسفر لبنان، فصل جديدي در زندگي منطقه و جهان\r\n\r\nرئيس جمهور گفت: طبيعي است که بيداري ملت‌ها زورگويان را ناراحت و عصباني مي‌کند، اما واکنش شتابزده آنها ملت‌ها را به اين نتيجه مي‌رساند که مسيرشان درست است.\r\n\r\nآقاي احمدي‌نژاد افزود: وقتي ببينيد آدم خطاکار از کار شما عصباني است، اين به ذهن متبادر مي‌شود که کارتان درست است.\r\n\r\nوي اضافه کرد:‌ اين هديه اي الهي است که به دست ملت ايران در حال اعطا به بشر است. رئيس جمهور گفت: نام ملت ايران هر جاي دنيا مي‌رويم، مي‌درخشد.\r\n\r\nوي افزود: امروز رابطه اي عميق، عاطفي و عاشقانه ميان ملت‌ها و ملت ايران ايجاد شده است؛ ملت‌هايي که فاصله‌هاي هزاران کيلومتري از ايران دارند و ارتباطات سياسي و اقتصادي چنداني هم با کشور ما ندارند.\r\n\r\nآقاي احمدي‌نژاد تصريح کرد: امروز وقتي نام ايران و ملت ايران مي‌آيد و يک مسئول ايراني را مي‌بينند، احساس همدلي مي‌کنند.\r\n\r\nوي افزود: امروز در کشورهاي گوناگون آن قدر احساس صميميت با ما دارند که خيلي راحت به گونه‌اي که گويي با خودشان يا بردارشان صحبت مي‌کنند، با ما حرف مي‌زنند.\r\n\r\nرئيس جمهور گفت‌: به لطف خدا اين اتفاق افتاده و عزت را خدا داده است، ولي ما در ميانه راه هستيم و نقطه هدف و آن مقصد خيلي بالاتر، زيباتر و باارزش‌تر از آني است که الان در آن قرار داريم. آقاي احمدي‌نژاد افزود: بايد به نقطه‌اي برسيم که در زندگي بشر غصه‌اي نباشد.\r\n\r\nوي درباره برخي پيامدهاي بين‌المللي سفر خود به لبنان گفت: اين سفر با عکس‌العمل تقريبا همه قشرها و رسانه‌ها مواجه شد؛ بسياري از روساي دولت‌ها، يا پيام دادند يا تماس گرفتند يا حضوري به ما گفتند که اتفاق عجيبي افتاده است.\r\n\r\nرئيس جمهور افزود: فکر مي‌کنم اين سفر پيوند و همگرايي را ميان دولت‌ها و ملت‌هاي منطقه بسيار تقويت کرد.\r\n\r\nآقاي احمدي‌نژاد گفت: اين برشي و مقطعي از وحدت ملت‌هاي منطقه بود که به رخ دشمنان کشيده شد. وي افزود: همه معادلات سياسي منطقه عوض شد؛ شخصي تعبيري را در نقطه مقابل تعبير امريکايي‌ها مطرح کرد که مي‌گفتند در پي خاورميانه بزرگ هستند و جنگ لبنان و غزه درد زايمان اين هدف بود.\r\n\r\nرئيس جمهور گفت: اين شخص گفت خاورميانه بزرگ متولد شد، اما به دست ملت ها و در نقطه مقابل دولت‌هاي فاسد و زورگو.\r\n\r\nآقاي احمدي‌نژاد افزود: مردم لبنان تجلي ملت‌هاي منطقه بودند.\r\n\r\nوي اضافه کرد: دشمنان به صورت قطعي متوجه شده‌اند که جايي در منطقه ما ندارند و بايد از منطقه و همه جاي دنيا بيرون بروند؛ از ملت‌هاي منطقه عذرخواهي و جبران کنند، بلکه ملت‌ها به آنها فرصت بدهند و از جناياتي که در طول دهه‌ها و سده‌ها مرتکب شده‌اند، گذشت کنند.\r\n\r\nرئيس جمهور تصريح کرد: از اين به بعد وارد فصل جديدي شده‌ايم و تعبير رهبر معظم انقلاب در خصوص اين سفر، درست است.\r\n\r\nآقاي احمدي‌نژاد افزود: نه اينکه بنده اين سفر را انجام داده‌ام چنين دستاوردهايي داشته است، آن اتفاقاتي که در لبنان افتاد فصل جديدي در زندگي منطقه و جهان است.\r\n\r\n\r\nموتور حرکت ملت ايران روشن شده است\r\n\r\nآقاي احمدي نژاد در ادامه گفتگو با شبکه اول سيما در پاسخ به پرسش مجري برنامه که به آغاز توليد بيو ايمپلنت با حضور رئيس جمهور اشاره کرد و پرسيد برنامه ايران در بحث توليد علم در افق چشم انداز 1404 چيست؟ پاسخ داد: براي توليد بيو ايمپلنت از کيسه جنين استفاده شده است که خواص بسيار زيادي دارد و سلول هاي بسيار ارزشمندي هستند که از آن براي پوشش چشمي، درمان زخم هاي چشمي، جراحي چشمي و زخم هاي درون بدن و ديگر کاربري ها استفاده مي شود.\r\n\r\nوي افزود: در اين موضوع ما فعلا در دنيا اول هستيم و تنها کشوري هستيم که صد درصد آزمايش هايش مثبت بوده است.\r\n\r\nرئيس جمهور گفت: بعد از ما آمريکا در مقام دوم قرار دارد و هشتاد درصد آزمايش هاي آنها جواب مثبت داده است.\r\n\r\nوي با بيان اين که بنابراين بحث منطقه اي نيست افزود: ‌به نظر مي رسد موتور حرکت ملت ايران روشن شده است و وقتي ملتي خود را باور کرد و اعتماد به نفس به دست آورد آن هم ملت ايران با آن سابقه و استعدادهاي الهي، حرکت و شتابش ديگر قابل اندازه گيري نيست.\r\n\r\nآقاي احمدي نژاد گفت: بنابراين 1404 دنياي ديگري است و قابل مقايسه با وضع موجود نيست و ايران 16 و 15 سال ديگر در نقطه ديگري از عالم قرار خواهد داشت.\r\n\r\nرئيس جمهور افزود: ‌اکنون مي گويند دو قدرت در دنيا وجود دارد يکي ايران و ديگري آمريکا و فکر مي کنم ان موقع همه چيز عوض شده است و زندگي ملت ايران و الهام بخشي ملت ايران در بالاترين سطح تعالي و ارزش هاي انساني قرار دارد.\r\n\r\nآقاي احمدي نژاد گفت: بنابراين ايران از لحاظ صنعتي، رفاه، شهرسازي،‌ معماري، هنر به نقطه اي مي رسد که قابل مقايسه با ديگران نيست.\r\n\r\nرئيس جمهور گفت: امروز هيچ کس در دنيا پيام ندارد، اميد نيست حتي در اروپا و آمريکا اميدي وجود ندارد و اعتماد به نفس خود را از دست داده اند و اميدي نيز ندارند اما ايران چه خبر است، سرشار از اميد، انگيزه است.\r\n\r\nوي افزود: ما جوانان را دعوت مي کنيم و پيچيدترين قطعات را به آنان مي دهيم با اعتماد به نفس از روي آن مي سازند.\r\n\r\nرئيس جمهور گفت: همين دستآوردهاي نمايشگاه نانو خيره کننده است. آقاي احمدي نژاد گفت: اکنون يک انقلاب صنعتي - علمي در ايران اتفاق مي افتد و يک انقلاب در نگرش ها اتفاق مي افتد.\r\n\r\nوي افزود: اکنون نگاه بچه 5 ساله ايراني نگاهش جهاني است و جوان دبيرستاني نگاهش به افق هاي بلند تاريخي و خودش را باور کرده است.\r\n\r\nرئيس جمهور افزود: وقتي به نسل هاي قبل و به نسل هاي خودمان برمي گرديم نگاه و افق ما محدود بود اکنون از بچه ها مي پرسيم 1000سال جلوتر از ما را نگاه مي کنند که اين نشانه اعتماد به نفس ، انگيزه و اراده است .\r\n\r\nآقاي احمدي نژاد گفت: امروز ملت ما اراده کرده است همه قله ها را فتح کند و خداوند متعال وعده داده است اگر ملتي اراده کند و خودش را براي تحقق ان اراده تجهيز کند حتما به آن مي رسد.\r\n\r\n\r\nبا 25درصد کاهش مصرف انرژي بودجه عمراني 1.5 برابر مي‌شود\r\n\r\nرئيس جمهور گفت: هنگامي که يارانه ها عمومي توزيع مي شود در واقع ثروت کشور هدر مي رود.\r\n\r\nآقاي احمدي نژاد با تشريح مزاياي اجراي قانون هدفمند کردن يارانه ها افزود: مردم با طرح آشنا هستند و من نمي خواهم مفصل توضيح دهم اما بعضي نکات را يادآوري مي کنم.\r\n\r\nرئيس جمهور گفت: دولت به طور عمومي يارانه ها را توزيع مي کند ، هنگامي که دولت قيمت ها را کنترل و سعي مي کند قيمتي را پايين نگه دارد و مابه التفاوت آن را خودش پرداخت کند معنايش اين است که يارانه ها را به شکل عمومي در جامعه توزيع مي کند.\r\n\r\nوي افزود: در چنين شرايطي دو، سه اتفاق رخ مي دهد ، هر کس بيشتر مصرف مي کند يارانه بيشتري از دولت مي گيرد درحالي که هدف از توزيع يارانه ها جبران فاصله ها و ضعف هاي قشرهاي خاص است اما نتيجه کاملاً معکوس است؛ کساني بيشتر استفاده مي کنند که بيشتر مصرف مي کنند.\r\n\r\nرئيس جمهور گفت: دولت با پرداخت يارانه ها مي خواهد توليد کشور سرپا بايستد و حرکت رو به رشدي داشته باشد.\r\n\r\nاحمدي نژاد افزود: اما اگر اين يارانه ها به شکل صحيح توزيع نشود و عمومي توزيع شود، باعث مي شود توليد کشور تنبل شود و کيفيت توليد پايين بيايد و مديريت توليد، ابتکار، نوآوري و خلاقيت را از دست بدهد.\r\n\r\nرئيس جمهور اضافه کرد: از اهداف اصلي اقتصاد اين است که مصرف در کشور بهينه باشد و يا ثروت کشور صحيح استفاده شود.\r\n\r\nآقاي احمدي نژاد گفت: با توزيع عمومي يارانه ها در واقع کالا ارزش خودش را ندارد، مصرف جايگاه خودش را پيدا نمي کند و اسراف و اتلاف منابع زياد مي شود.\r\n\r\n\r\nما چهار برابر متوسط جهاني انرژي مصرف مي کنيم.\r\n\r\nاحمدي نژاد با طرح اين پرسش ها که آيا ديگران انرژي استفاده نمي کنند ، تلويزيون و يخچال و اتو استفاده نمي کنند ، مسافرت نمي روند و صنعت ندارند ، گفت: همه اينها را دارند بعضي از کشورها از نظر صنعتي خيلي از ما پيشرفته تر هستند اما مصرف سرانه انرژي آنها از ما پايين تر است.\r\n\r\nرئيس جمهور همچنين با طرح اين پرسش که اين اتلاف از جيب چه کسي است گفت: از جيب کل ملت.\r\n\r\nاحمدي نژاد افزود: اين در حالي است که ما بيکاري ، محروميت و فقر داريم. خيلي سرمايه گذاري ها مي خواهيم انجام بدهيم ، منابع لازم را نداريم. استعداد ، خلاقيت و نوآوري هست اما امکان پشتيباني وجود ندارد.\r\n\r\nرئيس جمهور علت اين موارد را هدر رفتن منابع بيان کرد و گفت: اگر منابع در جاي خودش مصرف و به توليد و رفاه واقعي تبديل مي شد و سطح رفاه را بالا مي برد اشکالي نداشت.\r\n\r\nاحمدي نژاد ادامه داد: اما مي بينيم در سطح رفاه مساوي، مصرف بيشتري داريم و معنايش اين است که اتلاف منابع داريم.\r\n\r\nرئيس جمهور گفت: هنگامي که موتور يک خودرو خوب کار نمي کند و حوصله تعمير آن وجود ندارد اين اتفاق روي مي دهد در حالي که در دنيا براي هر 100 کيلومتر سفر با خودرو براي يک دهم ليتر کاهش بنزين برنامه ريزي مي شود.\r\n\r\nاحمدي نژاد افزود: اين برنامه ريزي به اين منظور صورت مي گيرد که اين کاهش را وقتي در مقياس ملي محاسبه کنيم مي بينيم که چقدر مي شود.\r\n\r\nوي اضافه کرد: 10 ميليون خودرو در ايران هست و 10 ميليون يک دهم در روز مي شود يک ميليون ليتر و اين مقدار بنزين به قيمت روز دنيا مي شود 600 تا 700 ميليون تومان بنزين در بازارهاي جهاني؛ اگر اين رقم را ضربدر سال کنيم مي شود 250 ميليارد تومان که بودجه عمراني يک استان است.\r\n\r\nرئيس جمهور افزود: همين يک دهم هاست که با تنظيم کاربراتور که هزينه اي و زحمتي نيز ندارد کاهش مي يابد.\r\n\r\nاحمدي نژاد گفت: با اين کار بودجه عمراني يک استان دو برابر مي شود.\r\n\r\nرئيس جمهور ادامه داد: حال مصرف انرژي ما در کشور چهار برابر متوسط جهاني است و ما نمي گوييم اين مصرف را به يک برسانيم بلکه مي گوييم به سه برسانيم يعني 25 درصد مصرف را کاهش دهيم.\r\n\r\nاحمدي نژاد گفت: چه اتفاقي خواهد افتاد، يعني سالي 30 ميليارد دلار، و اين رقم يعني انقلاب عمراني ، سرمايه گذاري و اشتغال.\r\n\r\nرئيس جمهور افزود: کل بودجه عمراني کشور 30 هزار تاست که معمولاً محقق نمي شود و در سال گذشته اين رقم 20 هزار تا بوده است.\r\n\r\nاحمدي نژاد گفت: يعني کل کارهاي عمراني از جمله فرودگاه ، جاده ، راه آهن ، مدرسه ، بيمارستان ، بندر ، کتابخانه ، شبکه هاي آب و برق ، 20 هزار تا بوده است.\r\n\r\nرئيس جمهور افزود: اگر فقط 25 درصد از مصرف انرژي را در کشور کاهش دهيم به طوري که هيچ فشاري هم به کسي وارد نشود معادل يک و نيم برابر بودجه عمراني کل کشور است.\r\n\r\n\r\nملت ايران از مرز توانمندي و اقتدار عبور کرده است\r\n\r\nرئيس جمهور گفت: ملت ايران از مرز توانمندي و اقتدار عبور کرده است.\r\n\r\nآقاي احمدي نژاد درباره تأثير تحريم ها گفت: تحريم کاغذ پاره است و واقعاً هم کاغذ پاره است شما در ايران بچرخيد ببينيد کي به اين موضوع حساس است.\r\n\r\nرئيس جمهور اضافه کرد: آنها اشتباه مي کنند ملت ايران از يک مرز عبور کرده است؛ از مرز توانمندي و اقتدار و آنها دستشان به ملت ايران نمي رسد.\r\n\r\n\r\nيارانه ها حذف نمي شود\r\n\r\nرئيس جمهور گفت: نمي خواهيم يارانه ها را حذف کنيم بلکه مي خواهيم آن را درست توزيع کنيم.\r\n\r\nوي افزود: حذف کردن يارانه ها با درست توزيع کردن آن متفاوت است.\r\n\r\nآقاي احمدي نژاد گفت: مثلا صنعت برق دو واحد يارانه مي خواهد که همان دو واحد را بايد به آن بدهيم نه اينکه 20 واحد بدهيم و 18 واحد آن تلف شود.\r\n\r\nرئيس جمهور افزود: حمل و نقل و ساير صنايع نيز همين طور است، مي خواهيم زندگي مردم را هدفمند کنيم که بخشي از آن دست خود مردم است و خودشان مديريت مي کنند.\r\n\r\nوي گفت: اگر يارانه ها را عمومي تقسيم کنيم ناعادلانه تقسيم مي شود آن را در اختيار مردم مي گذاريم تا خودشان هر طور صلاح دانستند مديريت کنند.\r\n\r\nاحمدي نژاد افزود: ممکن است برخي سوال کنند که چه نفعي براي کشور و دولت دارد.\r\n\r\nوي اضافه کرد: در پاسخ بايد بگوييم بزرگ ترين نفع دولت اولا صرفه جويي است.\r\n\r\nاحمدي نژاد گفت: دوم اينکه هر چيزي جاي خودش را پيدا مي کند آن وقت مديريت ها، خلاقيت ها و بهره وري ها بالا مي رود و ثروت ملي افزايش پيدا مي کند و همه چيز سرجاي خودش قرار مي گيرد.\r\n\r\nرئيس جمهور افزود: تصوير روشني از اقتصاد ارائه مي شود، توليد ملي و ثروت ملي بالا مي رود و باعث شکوفايي استعدادها مي شود.\r\n\r\nوي گفت: با اين کار به کساني که ناتوان مالي هستند فرصت داده مي شود و اين در جهت عدالت است.\r\n\r\nاحمدي نژاد افزود: جواني که استعداد دارد و امکانات ندارد به او فرصت داده مي شود.\r\n\r\n\r\nهدفمند کردن يارانه ها، مردمي ترين طرح اقتصادي\r\n\r\nرئيس جمهور گفت: اين طرح (هدفمند کردن يارانه ها) مردمي ترين طرح اقتصادي است که براي مردم، ‌با کمک مردم و به نفع مردم و کشور است.\r\n\r\nآقاي احمدي نژاد افزود: در تنظيم اين برنامه دولت تقريبا همه توان کارشناسي کشور را به کار گرفته است تا اين طرح به بهترين نحو ممکن اجرا شود.\r\n\r\nآقاي احمدي نژاد گفت: اولا همه تلاش ما اين است که با مديريت و کمک مردم اين طرح را اجرا کنيم.\r\n\r\nرئيس جمهور افزود: در ثاني توليد ملي افزايش يابد، ثالثا به زندگي مردم آسيبي وارد نشود و اگر تبعات احتمالي منفي هم دارد اين به حداقل برسد به همين خاطر براي هر بخش از جمله صنعت، کشاورزي، حمل و نقل، واردات، صادرات و ديگر بخش ها يک بسته تهيه کرده ايم که آنها چه کار بايد کنند تا کيفيت، مديريت، سودآوري و توليدشان بالا رود و اصلاح شود و باعث کاهش هزينه هايشان شود.\r\n\r\nوي گفت: با تمام بخش ها مشغول گفتگو هستيم، برنامه هايي را تنظيم کرديم و در حال تفاهم با آنها هستيم.\r\n\r\nآقاي احمدي نژاد گفت: در اجراي اين طرح فشار سنگيني در راه نيست اما ما با يک سازوکارهايي بايد شرايطي را به وجود آوريم که مردم مصرف خود را کنترل کنند و‌ منافعشان به جيب خودشان برود.\r\n\r\nوي افزود: ظرفيت هاي ايران خيلي زياد است و سرعت رشد آن مي تواند سه برابر شود.\r\n\r\nرئيس جمهور اضافه کرد: اجراي اين طرح نه تنها براي ما مفيد است بلکه براي نسل هاي آينده نيز مفيد خواهد بود.\r\n\r\nوي گفت: از همان روز اول که اين طرح اجرا مي شود مفيد است مثلا در خانواده اي که در ماه 600 کيلووات برق مصرف مي کند از اول ماه تصميم بگيرد که اين مصرف را به 500 کيلووات کاهش دهد، هم عمر لوازم زياد خواهد شد و هم هزينه100کيلووات به جيب سرپرست خانواده مي رود و مي تواند صرف ساير برنامه ها شود.\r\n\r\nآقاي احمدي نژاد گفت: در زمينه هاي گاز، بنزين‌، گازوئيل و هر چيزي ديگري که مربوط به انرژي است همينگونه است هر مصرفي که ما داريم و بتوانيم آن را مديريت کنيم بدون اين که رفاه خانواده بيايد پايين مي توانيم آن را صرفه جويي و خرج ساير مسائل کنيم.\r\n\r\n\r\n81 هزار تومان واريزي به صورت علي الحساب و براي دو ماه است\r\n\r\nرئيس جمهور در ادامه تشريح روند اجراي قانون هدفمندي يارانه ها گفت: دولت ابعاد مختلف اين طرح را با استفاده از همه ظرفيت کارشناسي کشور بررسي کرده است.\r\n\r\nآقاي احمدي نژاد افزود: در اقتصاد هيچ فردي مجزا از ديگران نيست و اقتصاد امري ملي و نه فردي است.\r\n\r\nرئيس جمهور اضافه کرد: با اجراي قانون هدفمندي يارانه ها قرار نيست که زندگي مردم به هم بريزد بلکه قرار است نظمي جديد و مديريت منابع را در زندگي تجربه کنيم.\r\n\r\nآقاي احمدي نژاد با اشاره به مراحل مختلف اجراي اين قانون از يک سال پيش گفت: لايحه دولت با کار کارشناسي گسترده و استفاده از همه صاحبنظران تدوين شد و مجلس نيز کار فشرده اي را بر روي اين لايحه انجام داد.\r\n\r\nوي افزود: اجراي اين قانون مدت هاست که آغاز شده است و مراحل مختلف شناسايي افراد متقاضي، پالايش اطلاعات و باز شدن حساب ها و کنترل آن از جمله اين مراحل است.\r\n\r\nآقاي احمدي نژاد گفت: مبالغ نقدي يارانه ها به مرور واريز مي شود زيرا ده ها ميليون حساب وجود دارد و بايد مسير کار کنترل شود.\r\n\r\nرئيس جمهور افزود: قسط بعدي يارانه ها با زدن يک کليد واريز مي شود.\r\n\r\nآقاي احمدي نژاد تصريح کرد: تلاش دولت اين است که در همه بخش ها روند مثبت آغاز شود و ترديدي نيست که با همکاري مردم وضعيت قريب به اتفاق آنان بهتر مي شود.\r\n\r\nرئيس جمهور همچنين از افرادي که از دريافت يارانه انصراف دادند، تشکر کرد و گفت: افرادي که داوطلبانه از دريافت يارانه خودداري کردند اين فرصت را دادند که به گروه هاي نيازمند بيشتر رسيدگي شود.\r\n\r\nآقاي احمدي نژاد گفت:81 هزار تومان واريزي به صورت علي الحساب و براي دو ماه است و در هر بار قبل از اين که اين مبلغ مصرف شود، علي الحساب بعدي واريز مي شود يعني اين که دولت جلوتر از مردم حرکت مي کند.\r\n\r\nرئيس جمهور افزود: اگر هزينه هاي مردم قرار است20هزار تومان افزايش يابد، حداقل براي شش دهک بيش از آن واريز مي شود و براي دو دهک نيز سربه سر خواهد بود.\r\n\r\nآقاي احمدي نژاد گفت: يارانه نقدي دو ماه، دو ماه واريز مي شود و اگر در روند کار بيشتر صرفه جويي شود، عدد علي الحساب تغيير مي کند.\r\n\r\nرئيس جمهور در پاسخ به سوالي درباره برخي مخالفت ها با اجراي اين طرح گفت: باورم اين است اگر کسي در ذهنش باشد که از موضوع هدفمندي بهره برداري سوء کند، حتماً ضرر مي کند.\r\n\r\nآقاي احمدي نژاد گفت: از رئيس کل بانک مرکزي خواسته ام که قيمت ارز واقعي شود اما وقتي ذخاير ارزي کافي داريم بايد پول ملي را تقويت کنيم.\r\n\r\nرئيس جمهور افزود: ممکن است در صادرات مشکلاتي بوجود بيايد اما در اين طرح براي جبران هزينه هاي صادر کنندگان پيش بيني هايي شده است که از طريق منابع ارزان قيمت و يارانه مستقيم جبران مي شود.\r\n\r\nآقاي احمدي نژاد با اشاره به موضوع حمل و نقل در هدفمندي يارانه ها گفت: بعنوان مثال اگر کاميوني از مشهد به تهران با بيست تن بار بيايد و در اين مسير به طور متوسط 500 ليتر گازوئيل مصرف کند و يک و نيم مسير بار داشته باشد، 750 ليتر گازوئيل مصرف مي کند.\r\n\r\nرئيس جمهور افزود: فرض کنيد قيمت گازوئيل صد تومان افزايش يابد، افزايش هزينه اين کاميون از محل مصرف سوخت 75 هزار تومان است که با توجه به کرايه 750 هزار توماني و حمل 20 هزار کيلو بار، افزايش قيمت در هر کيلو کالا 3 تا 4 تومان است.\r\n\r\nآقاي احمدي نژاد اضافه کرد: بنابراين افزايش يک درصدي از محل افزايش قيمت گازوئيل به قيمت کالا اضافه مي شود.\r\n\r\nرئيس جمهور همچنين نظارت بر اجراي اين طرح را شامل همکاري مردم، همکاري بخش هاي خدماتي و نظارت دولت برشمرد و گفت: مردم بايد خودشان مديريت کنند.\r\n\r\nآقاي احمدي نژاد افزود: دولت با همه توان در خدمت اجراي اين طرح است و در سطح کلان همه پيش بيني ها انجام شده است بنابراين بايد دست به دست هم بدهيم و يک بار براي هميشه اقليتي را که قصد سوء استفاده دارند، تنبيه کنيم و اين شدني است.\r\n\r\n\r\nمحتکران ضرر مي‌کنند\r\n\r\nرئيس جمهور درباره زمان اجراي قانون هدفمند کردن يارانه‌ها و سوءاستفاده‌هاي احتمالي عده‌اي گفت: مردم هر جا ديدند جوي درست شده است، خريد نکنند.\r\n\r\nآقاي احمدي‌نژاد افزود: مردم اطلاع دهند، ما بلافاصله جايگزين مي‌کنيم؛ برخوردي مي‌کنيم که مردم متوجه مي‌شوند کار درست است.\r\n\r\nوي گفت: مواد مهم و مورد نياز مردم را که معمولا بر زندگي مردم اثرگذار است، به اندازه کافي ذخيره کرده‌ايم؛ کالا هم به اندازه کافي و به اندازه دو تا سه سال مصرف در کشور وجود دارد و واردات و توليد در حال انجام شدن است.\r\n\r\nرئيس جمهور افزود: در قضيه ارز مي‌خواستند بازار را به هم بزنند، دولت وارد شد و ظرف کمتر از هفته قضيه را جمع کرد؛ الان آن قدر ارز داريم که هر کس هر قدر بخواهد به او مي‌دهيم.\r\n\r\nآقاي احمدي‌نژاد گفت:‌ پشتوانه ارزي، کالا، توان اقتصادي و توان توليد کشور به شدت بالاست.\r\n\r\nوي با تشکر از همراهي صنعتگران، کشاورزان، اصناف و تاجران با قانون هدفمند کردن يارانه‌ها افزود: جلسه مي‌گذاريم و مي‌بينيم آنها خودشان جلوتر از ما در حال مديريت و سازماندهي هستند.\r\n\r\nرئيس جمهور گفت: آنها طرح و کشور را مال خود مي دانند و مي خواهند به کشور جهش بدهند و آن را بسازند.\r\n\r\nآقاي احمدي‌نژاد سفارشي هم براي فروشندگان کالا داشت و افزود: خوب است سود بيشتر از فروش بيشتر داشته باشيم؛ البته طرز فکر قريب به اتفاق همين طور است.\r\n\r\nوي با بيان اينکه ظرفيت‌هاي خالي در کارخانه ها وجود دارد که بايد فعال شود، گفت: دولت صنايع را دسته‌بندي و پيش بيني کرده، آنها که سهم انرژي در توليدشان خيلي بالاست، به شکلي و ديگر بخش‌ها هم به شکل‌هاي ديگر در حد توان دولت پشتيباني خواهند شد.\r\n\r\nرئيس جمهور تاکيد کرد: اصل اتکاي ما بر اراده و همت اهالي صنعت، بازرگانان، کشاورزان و کسبه‌مان است.\r\n\r\nآقاي احمدي‌نژاد گفت: در فرهنگ ايراني اين وجود نداردکه کسي از ناراحتي ديگران سوء استفاده کند؛ اگر فضايي درست شود تا جنسي را با احتکار گران بفروشند که حلال نيست؛ اينکه خوب نيست نان مشکوک را سر سفره زن و بچه ببريم. اصلا دلمان مي‌آيد اين نان را بخوريم؟\r\n\r\nرئيس جمهور درباره نظارت و بازرسي حين اجراي قانون هدفمندسازي يارانه‌ها اظهار داشت: هم سازمان نظارت و بازرسي، هم خود اصناف و تعزيرات سازماندهي کرده‌اند؛ بدون تعارف و شوخي همه انبارها را بيرون مي‌ريزند.\r\n\r\nآقاي احمدي‌نژاد گفت: اينجا جايي نيست که بپذيريم کسي در گوشه‌اي به خود اجازه دهد کالايي را احتکار کند.\r\n\r\nوي افزود: ما آماده هستيم. تلفن‌ها اعلام مي شود؛ در تمام استان‌ها و شهرستان‌ها ستادها آماده هستند. هفته گذشته گفتند بعضي‌ها در حال ايجاد جهش هستند که به سرعت آمار همه انبارها درآمد، تذکر داديم.\r\n\r\nرئيس جمهور گفت: دولت به گونه‌اي عمل مي‌کند که هر کس احتکار کرد، ضرر کند، نمي‌دانند که ما چه زماني مي‌خواهيم قانون را اجرا کنيم؛ بگذاريد جنس را انبار کنند و هزينه انبارداري بدهند، آن وقت خواهند ديد که جنسشان به قيمتي که خريده‌اند، در بازار فروش نمي رود.\r\n\r\nآقاي احمدي‌نژاد تصريح کرد: الان جنس و کالا موضوعيت در کشور ندارد، همه کالاها در کشور موجود است؛ ذخيره ارزي و توليد داخلي هم به شدت بالاست.\r\n\r\nوي با بيان اينکه برخي گفته‌اند واردات برخي کالاها ممنوع شده است، گفت: ممنوعيتي وجود ندارد و طبق ضوابط اجناسي که ثبت استاندارد شود، مي‌آورند؛ در جريان صادرات، واردات و توليد داخلي ما اتفاقي نيفتاده است.\r\n\r\nرئيس جمهور افزود:‌ هر بخشي که قيمت انرژي براي آن تغيير کند، اتفاقي که قرار است برايش بيفتد، محاسبه شده است.\r\n\r\nآقاي احمدي‌نژاد با بيان اينکه حال ممکن است راننده‌اي بگويد هزينه روغن خودروي وي زياد شده است، افزود: اين قيمت زياد نمي شود؛ همه اينها را حساب کرده‌ايم.\r\n\r\nوي گفت:‌ البته همين جا بگويم که يکي از زحمت‌کش‌ترين قشرهاي جامعه ما، رانندگان فعال در شبکه حمل و نقلي هستند که در سرما و گرما، بيابان و شهر زحمت مي‌کشند و خدمت بزرگي مي‌کنند و شريان ارتباطي کشور هستند.\r\n\r\nرئيس جمهور افزود: دولت پيش بيني هايي کرده است که علاوه بر ارائه يارانه به خانواده‌هاي رانندگان، براي آنها بيمه و حساب قرض الحسنه براي گردش کارشان آماده کند و حداقل افزايش ممکن را هم برايشان پيش بيني کرده ايم تا آسيبي نبينند؛ البته در صنعت و کشاورزي و خدمات هم همين گونه است.\r\n\r\n\r\nنظرات بینندگان:\r\n\r\n>>>   با سلام\r\nسخنان دكتر را امشب از سيما مشاهده كرديم و با كمال اطمينان اعتقاد داريم كه حذف يارانه ها ضروري و مفيد است .\r\nولي نكاتي در اين رابطه كالا ضروري است تا بگوش مسئولين برسد :\r\n1 - همه ميدانند كه مثلاافزايش قيمت بنزين در يك كورس از 500 تومان به 800 تومان علي القاعده نبايستي منجر به افزايش كرايه هركدام از مسافرين به مبلغ نفري 300 - 400 تومتن گردد .\r\nاما مشكل كجاست كه اين اتفاق واقع ميگردد ؟ ايا دوات در اين خصوص كار كارشناسي نموده ؟ اگر نموده چرا سردار رويانيان به كلماتي مانند خداوكيلي و انصافا" و ..... متوسل ميگردد ؟\r\nبزرگترين علت اين جابجايي قيمت ها علاوه بر شوك رواني ناشي از حذف يارانه ها عدم وجود يك سيستم دقدق و فعال و فراگير و با اقتدار در زمينه كنترل قيمت ها و برخورد واقعي و حقيقي - نه نمايشي - با متخلفان است .\r\nلذا جاي اين سوال كاملا جدي وجود دارد كه دولت و مجلس ودستگاه قضا چه تمهيد مضاعفي براي اين مشكل انجام داده اند تا متخلف به سرعت عقاب گردد و مردم سريع اثر انتقال مشكلات به وراجع قانوني را بدون تبعيض و ...... مشاهده نمايند .\r\nلذا اين بخش و اطلاع رساني و تمركز بر روي كنترل خيلي بيش از ساير بخشها از جمله واريز يارانه ها اهميت دارد كه متاسفانه با كلماتي تكراري از انها عبور ميشود . روي اين فكر و برنامه ريزي نماييد .\r\n2 - در موارد برخورد با متخلفين و لزوم تعطيلي يك واحد صنفي مخصوصا واحد هايي مانند نانوايي و توزيع مواد پروتئيني و مشابه ان دولت بايد از هم اكنون منعطف و با ابرنامه باشد تا در همان ساعتي كه واحدي را تعطيل ميكند با مجوز قانوني و حكم حاكم شرع همان محل را با مديريت فردي ديگر و يا واحدي در مجاورت انرا براي لنگ نشدن كار مردم فعال كند و مردم اقتدار دولت و برنامه ريزي انرا لمس نمايند نه اينكه بعد از مدتها در اثر فشار مردم راضي به گران خريدن از همان واحد متخلف بشوند و به دولت و جمهوري اسلامي ناسزا بگويند و متخلف هم جري تر شود !\r\nمتذكر ميگردد اين مدلها بار ها تكرار شده و نبايستي مجددا ازموده شود كه : ازموده را ازمودن خطاست .\r\nسوال جدي تر اينكه دولت كه طراح و مجري حذف يارانه هاست در اين زمينه با مجلس و قضا سنگهاي خود را واكنده و مجاري قانوني و قضايي را گشوده است يا نه بعد از بروز مشكل به فكر خواهد افتاد ؟\r\nنكته اخر براي دكتر عزيز اينكه هم اكنون بسياري از مردم با چندين و يا چند ده مليون امكان سرمايه گذاري و مشاركت در بورس و ساير فعاليت هاي اقتصادي را نميابند . چطور دكتر عزيز از انها ميخواهد پس از افزايش قيمتها كه استفاده از يارانه نقدي را لازم مينمايد بلكه بيش از ان را - نسبت به سرمايه گذاري ذخيره سازي مبادرت كنند ؟\r\nواسالام . حيدر\r\n\r\n>>>   خداقوت انشاالله همانطور باشد كه رئيس جمهور محترم ميفرمايند ....\r\nسيدمهرداد\r\n\r\n>>>   يارانه اي که ميدهيد براي آن است که برق و گاز و بنزين را گران ميکنيد که اين يارانه کفاف آنرا نخواهد داداز طرف ديگر بقيه اقلام مثل گوشت کيلويي ۲۰ يا ۲۵ تومان را چه خواهيد کرد سياستهاي غلط شما جناب احمدي نژاد بريدن از دنيا و متلاشي کردن اقتصاد کشور و بيچارگي ملت است و بس\r\n\r\n>>>   از بیان و لهجه ورک گوئیش خوشم می آید.به تعبیر رهبری باید به مردم امید داد.ما آماده طرح هستیم\r\n\r\n>>>   چه خوب ده سال دیگه آمریکاییها صف کشیدن و التماس میکنند که اقامت ایران را بگیرند.\r\n\r\n>>>   میترسم بعدا اعلام کنندمبلغ واریزی برای دوسال است\r\n\r\n>>>   اخییییییییییییییششش\r\nخیالم راحت شد.دیگه همه چی درست شد\r\n\r\n>>>   خدا ميدونه كه چي ميشه احتمالا مرگ هم هدفمند مي كنند به حساب روحي خانوار يك اذرائيل واريز ميكنند تا هدف زندگيت (قبرستون) مشخص بشه؟\r\n\r\n>>>   وقتی یک فروشگاه از شرکت تعاونی درخواست پودر لباسشوئی می نماید می گویند فعلا نداریم چرا؟؟؟\r\n\r\n>>>   آقای احمدی نژاد وقتی با هدفمند کردن یارانه قیمت بنزین چهار برابر و قیمت گاز ده برابر و نان و برق و آب به همچنین , آیا هیچ عقل سلیمی قبول نمی کند که این افزایش قیمتها باعث کاهش قدرت خرید مردم می شود\r\nمن مایل هستم که شما به این سوال پاسخ دهید تا مردم هم پاسخ شما را هم بدانند\r\n\r\n>>>   بازرسی ها را زیاد کنید .الزامی ندارد بازرس ها از سازمان بازرسی کل کشور و یا تعزیزات باشند بلکه می توانید از هر کس در هر شغل که توانائی بازرس شدن را دارد و ازنظر فکری و اعتقادی همکاری با دولت را دوست دارد و دنبال منافع خود نیست استفاده کرده و دوره هائی را بگذارید که افراد متناسب بازرسی با نوع کار آشنا گردند.بدین ترتیب ما می توانیم کاملا بر اوضاع بازار و کشور تسلط یابیم.با تشکر از بابل ا.ع.ع\r\n\r\n>>>   سلام علیکم\r\nاززحمات جناب آقای احمدی نژ اد ممنون ومتشکریم امید است که خداوند به ایشان توفیق بیشتری عنایت فرماید تا بتواند بیشتر به بندگان خدا خدمت نماید ّا آرزوی پیروزی بیشتر برای ایشان از خداوند مسئلت مینماییم .\r\nغلامرضا خوشی کارمند باز نشسته آموزش وپرورش کرمان\r\n\r\n>>>   آقاي رئيس جمهور فرمودند : اگر خانواده ای توانایی دارد، از این سهم یارانه مبلغی مثلا 15-20 هزار تومن برای بچه ها کنار بذارن که تا 15-20 سال دیگه 50-60 میلیون تومن برای بچه ها پس انداز کرده باشند! 4800000=12*20*20000 یعنی چهار میلیون و هشتصد هزار تومان ِ بیست سال دیگر..\r\n\r\n>>>   چرا بخش هايي از صحبت هاي آقاي رئيس جمهور كه تشخيص داده ايد غير منطقي است سانسور كرده ايد ؟\r\n\r\n>>>   اگه حرفا فقط حرف نباشه\r\n\r\n>>>   "با 25درصد کاهش مصرف انرژی بودجه عمرانی 1.5 برابر می‌شود" غلط است\r\nاگر در صحبتهای رئیس جمهور دقت مکردید متوجه می شدید که با این کاهش معادل 1.5 برابر کل بودجه عمرانی کشور صرفه جویی می شود نه اینکه بودجه عمرانی 1.5 برابر می شود. در واقع بودجه عمرانی 2.5 برابر می شود.\r\n\r\n>>>   انشاءلله\r\n\r\n>>>   اين دولت از طرح تثبيت قيمتها رسيد به آزادسازي قيمتها ، در سهميه بندي بنزين از 120 ليتر رسيد به 60 ليتر ، والا ما مونديم دم خروس را باور كنيم يا قسم حضرت عباس رو - كاوه\r\n\r\n>>>   نمی دانیم قسم دروغ را باور کنیم یا دم روباه را !نمایندگان به اصطلاح محترم می گویند اگر بیش از 16هزار تومان باشد بیش از دو ماه نمی رسد . می گویند 12هزار میلیارد تومان بر 5/61میلیون نفر =195 هزار تومان بر 12 ماه =16هزار ودویست و پنجاه تومان در 5ماه =81هزار تومان لطفا توضیح دهید.\r\n\r\n>>>   خدا حفظت کنه احمدی نژاد\r\n\r\n>>>   خدا وکیلی یک کار درست حسابی که این دولت انجام داده بگید تا ما باورمون شه این مطالب صحیخ است.قطعا این موضوع مثل سایر موارد از قبیل اشتغال.تورم.مواد مخدر و...........شعاری بیش نیست.\r\n\r\n>>>   خدا کسانی را که در امر ساماندهی یارانه ها اختلال ایجاد می کنند را لعنت کند . آنها باید مطمئن باشند که در نهایت دولت در این امر تاریخی -انقلاب اقتصادی -پیروز می شود و کشور از این سرطان اقتصادی نجات پیدا میکند. ان شاء الله\r\n\r\n>>>   خدا کسانی را که در امر ساماندهی یارانه ها اختلال ایجاد می کنند را لعنت کند . آنها باید مطمئن باشند که در نهایت دولت در این امر تاریخی -انقلاب اقتصادی -پیروز می شود و کشور از این سرطان اقتصادی نجات پیدا میکند. ان شاء الله\r\n\r\n>>>   اگر واقعا يارانه ها تقسيم شود نه تعديل شود و جلوي فشار سرمايه داران بر قشر اسيب پذير گرفته شود\r\nدنيا و اخرت دولت مردان ما اصلاح شده است', '', '20101102114954', '2010/11/02', '1389/08/11', '11:49:54', '0'),
