INSERT INTO `news` (`id`, `newsId`, `fullDate`, `dateEN`, `dateFA`, `newsTime`, `author`, `accessLevel`, `newsGroup`, `newsTitle`, `brief`, `newsBody`, `lastDateModified`, `lastDateENModified`, `lastDateFAModified`, `lastTimeModified`, `lastOneModified`, `image`) VALUES
(35, 2147483647, '2010-08-22', '2010/08/22', '1389/05/31', '5:16:36', 'داریوش کبیر', 'سطح دسترسی', 'ایران شناسی', 'مردی کوچک', '<p style="text-align: left;" dir="rtl"> <strong><span style="font-family: tahoma,geneva,sans-serif;">ی<u>ک <span style="color: #0058ff;">فعال بازار نف</span><em style="color: #0058ff;">ت به خبرگزاری رویترز گفت: ما بعید می‌دانستیم که ایران بتواند بنزی</em></u><em style="color: #0058ff;">ن صاد</em><span style="color: #0058ff;">ر کند اما اکنون باید گفت این کار غیرممکن نبوده است. ساموئل سیزوک کارشناس نفتی موسسه آی.اچ.اس نیز گفت: این امکان </span>وجود دارد هر آن چه که ایرانی‌ها اعلام می‌کنند درست باشد </span></strong></p> \r\n  <p><img width="200" height="150" alt="wesnoth078.jpg" src="/IGW+/projects/qiauIgwPortalPhase2/modules/xinha/plugins/ImageManager/demo_images/wesnoth078.jpg" /> </p>', '<p dir="rtl" style="text-align: justify;"> <span style="font-family: tahoma,geneva,sans-serif;">ع<strong>غهغفهغ<u>ففغعهغفهغفهمتن خبر</u></strong></span></p> \r\n  <p dir="rtl" style="text-align: justify;"> <span style="font-family: tahoma,geneva,sans-serif;"><strong><u>آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولی</u>ن</strong> نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود آلودگی کامپیوترهای صنعتی ایران به این کرم جاسوس می‌تواند از این جهت برای مسئولین نگران کننده باشد که توسط این کرم جاسوس حتی ممکن است اطلاعات مربوط به فعالیت های هسته‌ای و نظامی ایران در ناشناخته ترین واحدهای صنعتی یا دانشگاهی قابل رصد شود </span></p>', '', '', '', '', NULL, 'upload/thumb20100822171636.jpg'),
